// Two-arg iterate: infinite stream (Java 9+)
Stream.iterate(1, n -> n * 2)
      .limit(5)
      .forEach(n -> System.out.print(n + " "));
System.out.println();

// Three-arg iterate: finite stream with predicate (Java 9)
Stream.iterate(1, n -> n < 20, n -> n * 2)
      .forEach(n -> System.out.print(n + " "));

List<Integer> ordered = List.of(1, 2, 3, 4, 5, 1, 2);

System.out.print("takeWhile: ");
ordered.stream()
       .takeWhile(n -> n < 4)
       .forEach(n -> System.out.print(n + " "));
System.out.println();

System.out.print("dropWhile: ");
ordered.stream()
       .dropWhile(n -> n < 4)
       .forEach(n -> System.out.print(n + " "));
